import pygame
import sys
import random
from task3 import GameGrid, Gem
from task0 import TETROMINO_SHAPES, GEM_COLORS, GRID_WIDTH, GRID_HEIGHT

# Pygame setup
CELL_SIZE    = 30
GRID_ORIGIN  = (20, 20)
PREVIEW_ORIGIN = (GRID_ORIGIN[0] + GRID_WIDTH * CELL_SIZE + 40, GRID_ORIGIN[1])
SCREEN_WIDTH  = GRID_ORIGIN[0] + GRID_WIDTH * CELL_SIZE + 200
SCREEN_HEIGHT = GRID_ORIGIN[1] + GRID_HEIGHT * CELL_SIZE + 40
FPS           = 60
FALL_EVENT    = pygame.USEREVENT + 1
FALL_INTERVAL = 500  # milliseconds

class Tetromino:
    def __init__(self, kind):
        self.kind     = kind
        self.shape    = TETROMINO_SHAPES[kind]
        self.color    = GEM_COLORS[kind]
        self.rotation = 0
        self.x        = GRID_WIDTH // 2 - 2
        self.y        = 0

    def blocks(self):
        cells = []
        for dx, dy in self.shape:
            x, y = dx, dy
            for _ in range(self.rotation):
                x, y = y, 3 - x
            cells.append((self.x + x, self.y + y))
        return cells

    def move(self, dx, dy, grid):
        new_positions = [(x + dx, y + dy) for x, y in self.blocks()]
        if all(0 <= x < grid.width and 0 <= y < grid.height and grid.get_cell(x, y) is None
               for x, y in new_positions):
            self.x += dx
            self.y += dy
            return True
        return False

    def rotate_cw(self, grid):
        old_rot = self.rotation
        self.rotation = (self.rotation + 1) % 4
        if any(not (0 <= x < grid.width and 0 <= y < grid.height and grid.get_cell(x, y) is None)
               for x, y in self.blocks()):
            self.rotation = old_rot

class Game:
    def __init__(self):
        pygame.init()
        self.screen    = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        pygame.display.set_caption("Tetris-Bejeweled Hybrid")
        self.clock     = pygame.time.Clock()
        self.font      = pygame.font.SysFont(None, 36)
        self.grid      = GameGrid(width=GRID_WIDTH, height=GRID_HEIGHT)
        self.score     = 0
        self.current   = self._next_tetromino()
        self.next_piece= self._next_tetromino()
        self.game_over = False
        pygame.time.set_timer(FALL_EVENT, FALL_INTERVAL)

    def _next_tetromino(self):
        kind = random.choice(list(TETROMINO_SHAPES.keys()))
        return Tetromino(kind)

    def lock_piece(self):
        for x, y in self.current.blocks():
            self.grid.set_cell(x, y, Gem(self.current.color))
        self.score += self.grid.process_clears()
        self.current = self.next_piece
        self.next_piece = self._next_tetromino()
        if any(self.grid.get_cell(x, y) is not None for x, y in self.current.blocks()):
            self.game_over = True

    def handle_input(self, event):
        if event.type == pygame.KEYDOWN and not self.game_over:
            if event.key == pygame.K_LEFT:
                self.current.move(-1, 0, self.grid)
            elif event.key == pygame.K_RIGHT:
                self.current.move(1, 0, self.grid)
            elif event.key == pygame.K_DOWN:
                if self.current.move(0, 1, self.grid):
                    self.score += 1
            elif event.key == pygame.K_UP:
                self.current.rotate_cw(self.grid)
        if event.type == FALL_EVENT and not self.game_over:
            if not self.current.move(0, 1, self.grid):
                self.lock_piece()

    def draw_grid(self):
        for y in range(self.grid.height):
            for x in range(self.grid.width):
                rect = pygame.Rect(
                    GRID_ORIGIN[0] + x * CELL_SIZE,
                    GRID_ORIGIN[1] + y * CELL_SIZE,
                    CELL_SIZE, CELL_SIZE
                )
                pygame.draw.rect(self.screen, (50, 50, 50), rect, 1)
                cell = self.grid.get_cell(x, y)
                if cell:
                    pygame.draw.rect(self.screen, cell.color,
                                     rect.inflate(-2, -2))

    def draw_current(self):
        for x, y in self.current.blocks():
            rect = pygame.Rect(
                GRID_ORIGIN[0] + x * CELL_SIZE,
                GRID_ORIGIN[1] + y * CELL_SIZE,
                CELL_SIZE, CELL_SIZE
            )
            pygame.draw.rect(self.screen, self.current.color,
                             rect.inflate(-2, -2))

    def draw_preview(self):
        label = self.font.render("Next:", True, (255, 255, 255))
        self.screen.blit(label, (PREVIEW_ORIGIN[0], PREVIEW_ORIGIN[1] - 30))
        for dx, dy in self.next_piece.shape:
            px = PREVIEW_ORIGIN[0] + dx * CELL_SIZE
            py = PREVIEW_ORIGIN[1] + dy * CELL_SIZE
            rect = pygame.Rect(px, py, CELL_SIZE, CELL_SIZE)
            pygame.draw.rect(self.screen, (100, 100, 100), rect, 1)
            pygame.draw.rect(self.screen, self.next_piece.color, rect.inflate(-2, -2))

    def draw_score(self):
        txt = self.font.render(f"Score: {self.score}", True, (255, 255, 255))
        self.screen.blit(txt, (PREVIEW_ORIGIN[0], PREVIEW_ORIGIN[1] + 4 * CELL_SIZE + 20))

    def draw_game_over(self):
        msg  = self.font.render("GAME OVER", True, (200, 0, 0))
        rect = msg.get_rect(center=(SCREEN_WIDTH // 2, SCREEN_HEIGHT // 2))
        self.screen.blit(msg, rect)

    def run(self):
        while True:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    pygame.quit()
                    sys.exit()
                self.handle_input(event)

            self.screen.fill((0, 0, 0))
            self.draw_grid()
            self.draw_current()
            self.draw_preview()
            self.draw_score()
            if self.game_over:
                self.draw_game_over()

            pygame.display.flip()
            self.clock.tick(FPS)

if __name__ == "__main__":
    Game().run()
